-- =====================================================
-- 2. Структурированные критерии перехода shoulder_rcr_supraspinatus
--    (JOIN на rehab_phases по program_type+phase_number → реальный phase_id)
--    Фаза 0 (prehab) и фаза 4 (терминальная) — без structured-критериев → не в WITH.
-- =====================================================
WITH criteria_data (
  phase_number, criterion_code, label, criterion_type,
  measurement_type, measurement_source,
  threshold_operator, threshold_value, threshold_value2,
  staleness_days, self_report_question, self_report_hint,
  position, is_required
) AS (VALUES
  -- Фаза 1 → Фаза 2 (покой и защита → восстановление подвижности)
  (1, 'passive_elevation_90',   'Пассивный подъём руки не менее 90° (к 6-й неделе — около 90–120°)',                          'instructor_check', NULL::varchar, NULL::varchar, NULL::varchar, NULL::numeric, NULL::numeric, 14::smallint, NULL::text, NULL::text, 10::smallint, TRUE),
  (1, 'passive_er_20_30',       'Пассивный поворот руки наружу с локтем у тела 20–30°',                                       'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 20::smallint, TRUE),
  (1, 'pain_controlled_p1',     'Боль под контролем, не более 3 из 10',                                                       'measurement',      'vas_score', 'pain', '<=', 3::numeric, NULL, 7::smallint, NULL, NULL, 30::smallint, TRUE),
  (1, 'sling_adherence_p1',     'Хорошее соблюдение мер предосторожности и режима слинга',                                    'self_report',      NULL, NULL, NULL, NULL, NULL, 7::smallint, 'Получается соблюдать меры предосторожности и носить слинг по режиму?', 'Слинг постоянно, без активных движений рукой и подъёма предметов', 40::smallint, TRUE),
  (1, 'healing_ok_p1',          'Адекватное заживление, мышцы плеча включаются, воспаление под контролем (оценка куратора)',   'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 50::smallint, FALSE),

  -- Фаза 2 → Фаза 3 (восстановление подвижности → укрепление)
  (2, 'passive_elevation_140',  'Пассивный подъём руки больше 140°, почти полный и без боли',                                 'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 10::smallint, TRUE),
  (2, 'active_elevation_120',   'Активный подъём руки не менее 120° без компенсаций',                                         'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 20::smallint, TRUE),
  (2, 'normal_er_neutral',      'Нормальный поворот руки наружу при локте у тела',                                            'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 30::smallint, TRUE),
  (2, 'pain_minimal_p2',        'Боль минимальная, не более 2 из 10',                                                         'measurement',      'vas_score', 'pain', '<=', 2::numeric, NULL, 7::smallint, NULL, NULL, 40::smallint, TRUE),
  (2, 'adl_below_shoulder_p2',  'Лёгкие несиловые бытовые дела ниже уровня плеча даются без боли',                            'self_report',      NULL, NULL, NULL, NULL, NULL, 7::smallint, 'Получается выполнять лёгкие бытовые дела ниже уровня плеча без боли?', 'Например, поесть, причесаться, одеться без боли в плече', 50::smallint, FALSE),
  (2, 'scapular_mechanics_p2',  'Нормальная работа лопатки, без компенсаций (оценка куратора)',                               'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 60::smallint, FALSE),

  -- Фаза 3 → Фаза 4 (укрепление → возврат к функции и спорту)
  (3, 'full_painfree_rom_p3',   'Полный безболезненный объём движений (и пассивный, и активный)',                             'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 10::smallint, TRUE),
  (3, 'strength_mmt_4_p3',      'Сила мышц плеча не менее 4 из 5 (оценка куратора)',                                          'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 20::smallint, TRUE),
  (3, 'er_ir_85_pct_p3',        'Для возврата к спорту: сила наружных и внутренних вращателей не менее 85% от здоровой руки',  'instructor_check', NULL, NULL, NULL, NULL, NULL, 30::smallint, NULL, NULL, 30::smallint, FALSE),
  (3, 'er_ir_ratio_60_p3',      'Соотношение силы наружных и внутренних вращателей не менее 60%',                             'instructor_check', NULL, NULL, NULL, NULL, NULL, 30::smallint, NULL, NULL, 40::smallint, FALSE),
  (3, 'painfree_strengthen_p3', 'Базовые дела и начальные силовые упражнения даются без боли',                                'self_report',      NULL, NULL, NULL, NULL, NULL, 7::smallint, 'Базовые дела и лёгкие силовые упражнения получаются без боли?', 'Оцените по нескольким занятиям с лентой и лёгкими весами', 50::smallint, TRUE),
  (3, 'scapular_kinematics_p3', 'Слаженная работа плеча и лопатки, нет признаков защемления или нестабильности (оценка куратора)', 'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 60::smallint, FALSE)
)
INSERT INTO phase_transition_criteria (
  phase_id, criterion_code, label, criterion_type,
  measurement_type, measurement_source,
  threshold_operator, threshold_value, threshold_value2, staleness_days,
  self_report_question, self_report_hint,
  position, is_required, is_active
)
SELECT
  p.id, cd.criterion_code, cd.label, cd.criterion_type,
  cd.measurement_type, cd.measurement_source,
  cd.threshold_operator, cd.threshold_value, cd.threshold_value2, cd.staleness_days,
  cd.self_report_question, cd.self_report_hint,
  cd.position, cd.is_required, TRUE
FROM criteria_data cd
JOIN rehab_phases p ON p.program_type = 'shoulder_rcr_supraspinatus' AND p.phase_number = cd.phase_number
ON CONFLICT (phase_id, criterion_code) DO NOTHING;

COMMIT;
